// 简化版Cannon.js占位（仅包含基本API定义）
(function(root) {
    // Cannon.js命名空间
    const CANNON = root.CANNON = {};
    
    // Vec3: 3D向量
    CANNON.Vec3 = class Vec3 {
        constructor(x = 0, y = 0, z = 0) {
            this.x = x;
            this.y = y;
            this.z = z;
        }
        
        set(x, y, z) {
            this.x = x;
            this.y = y;
            this.z = z;
            return this;
        }
        
        copy(v) {
            this.x = v.x;
            this.y = v.y;
            this.z = v.z;
            return this;
        }
        
        add(v) {
            this.x += v.x;
            this.y += v.y;
            this.z += v.z;
            return this;
        }
        
        scale(s) {
            this.x *= s;
            this.y *= s;
            this.z *= s;
            return this;
        }
    };
    
    // Quaternion: 四元数
    CANNON.Quaternion = class Quaternion {
        constructor(x = 0, y = 0, z = 0, w = 1) {
            this.x = x;
            this.y = y;
            this.z = z;
            this.w = w;
        }
        
        setFromAxisAngle(axis, angle) {
            const halfAngle = angle / 2;
            const s = Math.sin(halfAngle);
            this.x = axis.x * s;
            this.y = axis.y * s;
            this.z = axis.z * s;
            this.w = Math.cos(halfAngle);
            return this;
        }
    };
    
    // Shape: 碰撞形状（基类）
    CANNON.Shape = class Shape {
        constructor() {
            this.type = 'Shape';
        }
    };
    
    // Sphere: 球体
    CANNON.Sphere = class Sphere extends CANNON.Shape {
        constructor(radius) {
            super();
            this.type = 'Sphere';
            this.radius = radius;
        }
    };
    
    // Box: 盒子
    CANNON.Box = class Box extends CANNON.Shape {
        constructor(halfExtents) {
            super();
            this.type = 'Box';
            this.halfExtents = halfExtents;
        }
    };
    
    // Plane: 平面（用于地面）
    CANNON.Plane = class Plane extends CANNON.Shape {
        constructor() {
            super();
            this.type = 'Plane';
        }
    };
    
    // Body: 刚体
    CANNON.Body = class Body {
        constructor(options = {}) {
            this.id = CANNON.Body._nextId++;
            this.mass = options.mass !== undefined ? options.mass : 0;
            this.position = new CANNON.Vec3();
            this.velocity = new CANNON.Vec3();
            this.force = new CANNON.Vec3();
            this.quaternion = new CANNON.Quaternion();
            this.angularVelocity = new CANNON.Vec3();
            this.shapes = [];
            this.material = options.material || null;
            
            if (options.shape) {
                this.addShape(options.shape);
            }
            
            this.position.copy(options.position || new CANNON.Vec3());
        }
        
        addShape(shape) {
            this.shapes.push(shape);
        }
        
        addEventListener(type, callback) {
            if (!this._listeners) this._listeners = {};
            if (!this._listeners[type]) this._listeners[type] = [];
            this._listeners[type].push(callback);
        }
        
        dispatchEvent(event) {
            if (this._listeners && this._listeners[event.type]) {
                this._listeners[event.type].forEach(cb => cb(event));
            }
        }
    };
    
    CANNON.Body._nextId = 0;
    
    // World: 物理世界
    CANNON.World = class World {
        constructor() {
            this.gravity = new CANNON.Vec3(0, -9.8, 0);
            this.bodies = [];
            this.broadphase = new CANNON.NaiveBroadphase();
            this.solver = new CANNON.GSSolver();
            this.allowSleep = false;
        }
        
        addBody(body) {
            this.bodies.push(body);
            body.world = this;
        }
        
        removeBody(body) {
            const idx = this.bodies.indexOf(body);
            if (idx > -1) {
                this.bodies.splice(idx, 1);
            }
        }
        
        step(dt) {
            // 简化版：只应用重力
            const gravity = this.gravity;
            
            for (const body of this.bodies) {
                if (body.mass > 0) {
                    // 应用重力
                    body.velocity.x += gravity.x * dt;
                    body.velocity.y += gravity.y * dt;
                    body.velocity.z += gravity.z * dt;
                    
                    // 更新位置
                    body.position.x += body.velocity.x * dt;
                    body.position.y += body.velocity.y * dt;
                    body.position.z += body.velocity.z * dt;
                    
                    // 简单边界检测（地面）
                    if (body.position.y < 0.5) {
                        body.position.y = 0.5;
                        body.velocity.y = -body.velocity.y * 0.6; // 反弹
                        body.velocity.x *= 0.9; // 摩擦力
                        body.velocity.z *= 0.9;
                        
                        // 触发碰撞事件
                        body.dispatchEvent({ type: 'collide', body: body });
                    }
                }
            }
        }
    };
    
    // NaiveBroadphase: 简单粗检测
    CANNON.NaiveBroadphase = class NaiveBroadphase {
        constructor() {}
    };
    
    // GSSolver: 求解器
    CANNON.GSSolver = class GSSolver {
        constructor() {
            this.iterations = 10;
        }
    };
    
    // Material: 材质
    CANNON.Material = class Material {
        constructor(name = '') {
            this.name = name;
        }
    };
    
    // ContactMaterial: 接触材质
    CANNON.ContactMaterial = class ContactMaterial {
        constructor(materialA, materialB, options = {}) {
            this.materialA = materialA;
            this.materialB = materialB;
            this.friction = options.friction !== undefined ? options.friction : 0.3;
            this.restitution = options.restitution !== undefined ? options.restitution : 0.3;
        }
    };
    
    console.log('[Cannon.js] 本地简化版已加载（基础物理功能）');
})(typeof window !== 'undefined' ? window : this);
